1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { processScenario } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // Quote: empty / fee
7	  it("should return premium of 5 G for empty item list (just processing fee)", () => {
8	    const scenario = {
9	      customer: { name: "Test Customer", years: 0, contracts: 0 },
10	      steps: [{ type: "quote", items: [] }],
11	    };
12	    expect(processScenario(scenario)).toEqual({ results: [{ premium: 5 }] });
13	  });
14	
15	  // Quote: single base items (with first-insurance +10% policy modifier and 5 G fee)
16	  it.todo("should quote a single Sword (base 100 G + 10% first insurance + 5 G fee)");
17	  it.todo("should quote a single Amulet (base 60 G + 10% first insurance + 5 G fee)");
18	  it.todo("should quote a single Staff (base 80 G + 10% first insurance + 5 G fee)");
19	  it.todo("should quote a single Potion (base 40 G + 10% first insurance + 5 G fee)");
20	  it.todo("should quote a single Rune component (base 25 G + 10% first insurance + 5 G fee)");
21	  it.todo("should quote a single Moonstone component (base 25 G + 10% first insurance + 5 G fee)");
22	
23	  // Quote: multiple items summed
24	  it.todo("should sum premiums for two different items in a single quote");
25	
26	  // Quote: block of 3 alike components
27	  it.todo("should apply block-of-3 special premium (60 G) for three alike runes instead of 75 G");
28	  it.todo("should apply block-of-3 special premium (60 G) for three alike moonstones instead of 75 G");
29	
30	  // Item-specific surcharges
31	  it.todo("should apply +50% cursed surcharge on the item base premium");
32	  it.todo("should apply +30% high-enchantment surcharge for enchantment >= 5");
33	  it.todo("should stack cursed and high-enchantment surcharges on the same item base");
34	
35	  // Policy-wide modifiers
36	  it.todo("should apply -20% loyalty discount for customers with >= 2 years");
37	  it.todo("should apply -15% follow-up discount for contracts after the first");
38	
39	  // Rounding
40	  it.todo("should round premium UP to a whole G");
41	
42	  // Claim: basic deductible
43	  it.todo("should subtract 100 G deductible per damaged item from a basic claim");
44	
45	  // Claim: payout cap
46	  it.todo("should cap total payout at 2x the policy insurance sum");
47	
48	  // Claim: high enchantment clause
49	  it.todo("should reimburse 50% of damage when item has enchantment >= 8 (then deductible)");
50	
51	  // Claim: dragon material clause
52	  it.todo("should reimburse full damage when item is made of dragon material");
53	
54	  // Claim: both clauses combined
55	  it.todo("should apply 50% rule first then deductible when both high-enchantment and dragon material apply");
56	
57	  // Claim: rounding
58	  it.todo("should round payouts DOWN to a whole G");
59	
60	  // CLI errors (basic validation)
61	  it.todo("should error on unknown item type in a quote");
62	  it.todo("should error on a claim damages array that does not match policy items");
63	  it.todo("should error on negative damage amount in a claim");
64	});
